///|
fn main {
  let app = @mocket.new()

  // Register global middleware
  app
  ..use_middleware(logger_middleware())
  ..use_middleware(@cors.handle_cors())

  // Text Response
  ..get("/", _event => "⚡️ Tadaa!")

  // Hello World
  ..on("GET", "/hello", _ => "Hello world!")
  ..group("/api", group => {
    // 添加组级中间件
    group.use_middleware((event, next) => {
      println(
        "🔒 API Group Middleware: \{event.req.http_method} \{event.req.url}",
      )
      next()
    })
    group.get("/hello", _ => "Hello world!")
    group.get("/json", _ => {
      ({ "name": "John Doe", "age": 30, "city": "New York" } : Json)
    })
  })

  // JSON Response
  ..get("/json", _event => {
    ({ "name": "John Doe", "age": 30, "city": "New York" } : Json)
  })

  // Async Response
  ..get("/async_data", fn(_event) noraise {
    ({ "name": "John Doe", "age": 30, "city": "New York" } : Json)
  })

  // Dynamic Routes
  // /hello2/World = Hello, World!
  ..get("/hello/:name", event => {
    let name = event.params.get("name").unwrap_or("World")
    "Hello, \{name}!"
  })
  // /hello2/World = Hello, World!
  ..get("/hello2/*", event => {
    let name = event.params.get("_").unwrap_or("World")
    "Hello, \{name}!"
  })

  // Wildcard Routes
  // /hello3/World/World = Hello, World/World!
  ..get("/hello3/**", event => {
    let name = event.params.get("_").unwrap_or("World")
    "Hello, \{name}!"
  })

  // Echo Server
  ..post("/echo", e => e.req)

  // 404 Page
  .use_middleware(not_found_middleware())

  // Print Server URL
  for path in app.mappings.keys() {
    println("\{path.0} http://localhost:4000\{path.1}")
  }

  // Serve
  app.serve(port=4000)
}

///|
pub fn not_found_middleware() -> @mocket.Middleware {
  (event, next) => {
    let res = next()
    res.options(event.res)
    if event.res.status_code == NotFound {
      @mocket.html(
        (
          #|<html>
          #|<body>
          #|  <h1>Custom 404</h1>
          #|</body>
          #|</html>
        ),
      )
    } else {
      res
    }
  }
}

///|
fn logger_middleware() -> @mocket.Middleware {
  (event, next) => {
    let start_time = @env.now()
    let res = next()
    let duration = @env.now() - start_time
    println("\{event.req.http_method} \{event.req.url} - \{duration}ms")
    res
  }
}

///|
using @mocket {type HttpResponse}

///|
struct Person {
  name : String
  age : Int
} derive(ToJson, FromJson)

///|
impl @mocket.BodyReader for Person with from_request(req) -> Person raise {
  @json.from_json(req.body())
}

///|
fn main {
  let app = @mocket.new()

  // Text Response
  app
  ..get("/", _event => "⚡️ Tadaa!")

  // Object Response
  ..get("/json", _event => { name: "oboard", age: 21 }.to_json())

  // JSON Request
  // curl --location 'localhost:4000/json' \
  // --header 'Content-Type: application/json' \
  // --data '{
  //     "name": "oboard",
  //     "age": 21
  // }'
  ..post("/json", event => {
    try {
      let person : Person = event.req.body()
      HttpResponse::new(OK).body(
        "Hello, \{person.name}. You are \{person.age} years old.",
      )
    } catch {
      _ => HttpResponse::new(BadRequest).body("Invalid JSON")
    }
  })

  // Echo Server
  ..post("/echo", e => e.req)

  // 404 Page
  .get("/404", _ => {
    HttpResponse::new(NotFound).body(
      @mocket.html(
        (
          #|<html>
          #|<body>
          #|  <h1>404</h1>
          #|</body>
          #|</html>
        ),
      ),
    )
  })

  // Print Server URL
  for path in app.mappings.keys() {
    println("\{path.0} http://localhost:4000\{path.1}")
  }

  // Serve
  app.serve(port=4000)
}

///|
using @runtime {trait IsCell}

///|
priv struct TypedCell[Model, Msg] {
  model : Ref[Model]
  dispatcher : Dispatcher[Msg]
  dispatch : (Msg) -> Cmd
  update : (Dispatch[Msg], Msg, Model) -> (Cmd, Model)
  view : (Dispatch[Msg], Model) -> @html.Html
  flags : @runtime.Flags
}

///|
/// Message dispatcher type used by a `Cell`.
///
/// Calling `dispatch(msg)` returns a `Cmd` that enqueues `msg` into the cell's
/// update loop.
pub type Dispatch[Msg] = (Msg) -> Cmd

///|
impl[Model, Msg] IsCell for TypedCell[Model, Msg] with step(self, scheduler) {
  if self.dispatcher.inbox.pop() is Some(msg) {
    let (cmd, model) = (self.update)(self.dispatch, msg, self.model.val)
    self.model.val = model
    scheduler.add(cmd)
    self.flags.mark_dirty()
  } else {
    // violate the invariant
  }
}

///|
impl[Model, Msg] IsCell for TypedCell[Model, Msg] with view(self) {
  (self.view)(self.dispatch, self.model.val).0
}

///|
impl[Model, Msg] IsCell for TypedCell[Model, Msg] with flags(self) {
  self.flags
}

///|
priv struct Dispatcher[Msg] {
  id : @runtime.Id
  inbox : @queue.Queue[Msg]
}

///|
fn[Msg] Dispatcher::message(self : Self[Msg], msg : Msg) -> Cmd {
  // carry the drain (which own model and update) in message will cause memeory leak in RC
  @runtime.message(self.id, () => self.inbox.push(msg))
}

///|
/// A cell that encapsulates model, update, and view.
struct Cell(&IsCell)

///|
/// Render this cell as `Html`.
pub fn Cell::view(self : Self) -> Html {
  Html::from_vnode(@runtime.VNode::slot(self.0))
}

///|
/// Create a stateful cell with full `model`/`update`/`view` functionality.
///
/// Type parameters:
///
/// - `Model`: a custom type you need to defiend, represent the state of this cell.
/// - `Msg`: a custom `enum` you need to defined, represent the events of this cell. 
///
/// Parameters:
///
/// - `model : Model`:
///    initial `Model` value of the cell.
/// 
/// - `update : (Dispatch[Msg], Msg,Model) -> (Cmd,Model)`:
///    Describe how to compute new `Model` from `Msg` and old `Model`. 
///    This callback also receives a `Dispatch[Msg]`, which converts a `Msg`
///    into a `Cmd`.
/// 
/// - `view : (Dispatch[Msg], Model) -> Html`:
///    Describe how to compute `Html` from `Model`.
///    This callback also receives a `Dispatch[Msg]`, which converts a `Msg`
///    into a `Cmd`.
///
/// ## The update loop
///
/// ```text
/// ┌─────────────────┐
/// │                 ▼
/// │            ┌──────────┐
/// │            │   user   │
/// │            └────┬─────┘
/// │                 │ msg,model
/// │                 ▼
/// │           ┌────────────┐   msg,model
/// │           │  update()  │◄────────────┐
/// │           └──┬───────┬─┘             │
/// │    none,model│       │               │
/// │              ▼       │               │
/// │         ┌────────┐   │cmd,model      │
/// │         │ view() │   │               │
/// │         └────┬───┘   │               │
/// │              │       │               │
/// │          html│       ▼               │
/// │              │   ┌─────────┐         │
/// └──────────────┘   │ runtime │─────────┘
///                    └─────────┘
/// ```
/// 
/// This update loop is a bit more complex than `simple_cell`, but follows the
/// same `model -> update -> view` flow.
///
/// The difference is that `update` also returns a command representing a managed
/// side effect. That side effect is executed by the runtime and may produce
/// another message.
///
pub fn[Model, Msg] cell(
  model~ : Model,
  update~ : (Dispatch[Msg], Msg, Model) -> (Cmd, Model),
  view~ : (Dispatch[Msg], Model) -> Html,
) -> Cell {
  let flags = @runtime.Flags::new()
  let dispatcher = { id: flags.id(), inbox: @queue.new() }
  let dispatch = m => dispatcher.message(m)
  let model = @ref.new(model)
  Cell({ view, update, dispatcher, dispatch, model, flags })
}

///|
/// Create a cell and also return its `Dispatch`.
///
/// This is useful when messages need to be sent from outside.
/// 
/// Type parameters:
///
/// - `Model`: a custom type you need to defiend, represent the state of this cell.
/// - `Msg`: a custom `enum` you need to defined, represent the events of this cell. 
///
/// Parameters:
///
/// - `model : Model`:
///    initial `Model` value of the cell.
/// 
/// - `update : (Dispatch[Msg], Msg,Model) -> (Cmd,Model)`:
///    Describe how to compute new `Model` from `Msg` and old `Model`. 
///    This callback also receives a `Dispatch[Msg]`, which converts a `Msg`
///    into a `Cmd`.
/// 
/// - `view : (Dispatch[Msg], Model) -> Html`:
///    Describe how to compute `Html` from `Model`.
///    This callback also receives a `Dispatch[Msg]`, which converts a `Msg`
///    into a `Cmd`.
///
/// ## The update loop
///
/// ```text
/// ┌─────────────────┐
/// │                 ▼
/// │            ┌──────────┐
/// │            │   user   │
/// │            └────┬─────┘
/// │                 │ msg,model
/// │                 ▼
/// │           ┌────────────┐   msg,model
/// │           │  update()  │◄────────────┐
/// │           └──┬───────┬─┘             │
/// │    none,model│       │               │
/// │              ▼       │               │
/// │         ┌────────┐   │cmd,model      │
/// │         │ view() │   │               │
/// │         └────┬───┘   │               │
/// │              │       │               │
/// │          html│       ▼               │
/// │              │   ┌─────────┐         │
/// └──────────────┘   │ runtime │─────────┘
///                    └─────────┘
/// ```
/// 
/// This update loop is a bit more complex than `simple_cell`, but follows the
/// same `model -> update -> view` flow.
///
/// The difference is that `update` also returns a command representing a managed
/// side effect. That side effect is executed by the runtime and may produce
/// another message.
///
pub fn[Model, Msg] cell_with_dispatch(
  model~ : Model,
  update~ : (Dispatch[Msg], Msg, Model) -> (Cmd, Model),
  view~ : (Dispatch[Msg], Model) -> Html,
) -> (Dispatch[Msg], Cell) {
  let flags = @runtime.Flags::new()
  let dispatcher = { id: flags.id(), inbox: @queue.new() }
  let dispatch = m => dispatcher.message(m)
  let model = @ref.new(model)
  (dispatch, Cell({ view, update, dispatcher, dispatch, model, flags }))
}

///|
/// Create a cell with simplified `model`/`update`/`view`.
/// 
/// Type parameters:
/// 
/// - `Model`: a custom type you need to defiend, represent the state of this cell.
/// - `Msg`: a custom `enum` you need to defined, represent the events of this cell. 
/// 
/// Parameters:
/// 
/// - `model : Model`: initial Model value of the cell.
/// - `update : (Msg, Model) -> Model`: describe how to compute new Model from Msg and old Model.
/// - `view : (Dispatch[Msg], Model) -> Html`: describes how to render Html from Model.
///   This callback also receives a dispatch argument, which converts a Msg
///   into a Cmd.
/// 
/// ## The update loop
///
/// ```text
///    ┌──────┐
///    │ user │◀─────────┐
///    └──────┘          │
///        │ msg, model  │
///        ▼             │
///  ┌──────────┐        │
///  │ update() │        │ html
///  └──────────┘        │
///        │ model       │
///        ▼             │
///   ┌────────┐         │
///   │ view() │─────────┘
///   └────────┘
/// ```
/// 
/// At startup, the initial `model` is rendered as `Html` by `view`. The rendered 
/// HTML can include message-producing command, for example:
/// 
/// ```moonbit nocheck
/// button(on_click=dispatch(MyMsg), "click me")
/// ```
///
/// When the user clicks the button, `MyMsg` is sent to `update` with the current
/// model. `update` then computes the next model from that message, and the new
/// model is rendered again by `view`.
/// 
/// ## Example 
/// 
/// ```moonbit check
/// test "counter" {
///   struct Model {
///     count : Int
///   }
///   enum Msg {
///     Click
///   }
///   let app = @rabbita.simple_cell(
///     model={ count: 0 },
///     update=(msg, model) => {
///       match msg {
///         Click => { count: model.count + 1 }
///       }
///     },
///     view=(dispatch, model) => {
///       div([
///         h1("You clicked \{model.count} times."),
///         button(on_click=dispatch(Click), "+"),
///       ])
///     },
///   )
///   ignore(app) // use `new(app).mount("id")` in client
/// }
/// ```
pub fn[Model, Msg] simple_cell(
  model~ : Model,
  update~ : (Msg, Model) -> Model,
  view~ : (Dispatch[Msg], Model) -> Html,
) -> Cell {
  cell(model~, update=(_, msg, model) => (none, update(msg, model)), view~)
}

///|
pub fn[Model, Msg] simple_cell_with_dispatch(
  model~ : Model,
  update~ : (Msg, Model) -> Model,
  view~ : (Dispatch[Msg], Model) -> Html,
) -> (Dispatch[Msg], Cell) {
  let flags = @runtime.Flags::new()
  let dispatcher = { id: flags.id(), inbox: @queue.new() }
  let dispatch = m => dispatcher.message(m)
  let model = @ref.new(model)
  (
    dispatch,
    Cell({
      view,
      update: (_, msg, model) => (none, update(msg, model)),
      dispatcher,
      dispatch,
      model,
      flags,
    }),
  )
}

///|
/// Create a static cell that always renders the same `Html`.
///
/// Rather than use `static_cell`, it's recommend to wrap a function that return html directly:
/// 
/// ```moonbit nocheck
/// fn button(text : String, on_click~ : Cmd) -> Html {
///   @html.button(style=["..."], on_click~, text)
/// }
/// ```
pub fn static_cell(html : Html) -> Cell {
  cell(model=(), update=fn(_, _ : Unit, _ : Unit) { (none, ()) }, view=fn(
    _,
    _,
  ) {
    html
  })
}

///|
using @runtime {trait Scheduler, type Cmd}

///|
#cfg(target="js")
pub(all) enum Expecting[Msg, Model] {
  Json((Result[Model, String]) -> Msg, (Json) -> Result[Model, String])
  Text((Result[String, String]) -> Msg)
}

///|
#cfg(target="js")
pub(all) enum Body {
  Json(Json)
  Text(String)
  Empty
}

///|
#cfg(target="js")
fn Body::content_type(self : Body) -> String {
  match self {
    Json(_) => "application/json"
    Text(_) => "text/plain"
    Empty(_) => "text/plain"
  }
}

///|
#cfg(target="js")
fn Body::stringfiy(self : Body) -> String {
  match self {
    Json(json) => json.stringify()
    Text(text) => text
    Empty => ""
  }
}

///|
#cfg(target="js")
extern "js" fn js_request(
  url : String,
  http_method : String,
  content_type~ : String,
  body~ : String,
  has_body~ : Bool,
  succeed~ : (String) -> Unit,
  failed~ : (String) -> Unit,
) =
  #| (url,method,contentType,body,hasBody,succeed,failed) => {
  #|   var config = { method: method, headers: { 'Content-Type': contentType } }; 
  #|   if (hasBody) { config.body = body };
  #|   fetch(url, config)
  #|     .then(response => response.text())
  #|     .then(json => succeed(json))
  #|     .catch(error => {
  #|       failed(error.toString())
  #|     })
  #| }

///|
#cfg(target="js")
fn[Model] request(
  url : String,
  http_method : String,
  expect~ : Expecting[Cmd, Model],
  body~ : Body,
) -> Cmd {
  let launch = fn(scheduler : &Scheduler) {
    let has_body = match body {
      Empty => false
      _ => true
    }
    let content_type = body.content_type()
    let body = body.stringfiy()
    match expect {
      Json(f, decoder) =>
        js_request(
          url,
          http_method,
          has_body~,
          body~,
          content_type~,
          succeed=str => {
            let result = Ok(@json.parse(str)) catch {
              _ => Err("Json parse error")
            }
            scheduler.add(f(result.bind(decoder)))
          },
          failed=msg => scheduler.add(f(Err("Http request failed:\{msg}"))),
        )
      Text(f) =>
        js_request(
          url,
          http_method,
          has_body~,
          body~,
          content_type~,
          succeed=str => scheduler.add(f(Ok(str))),
          failed=msg => scheduler.add(f(Err("Http request failed:\{msg}"))),
        )
    }
  }
  @runtime.effect(kind=Immediately, launch)
}

///|
/// Create a command to send a GET request.
#cfg(target="js")
pub fn[Model] get(url : String, expect~ : Expecting[Cmd, Model]) -> Cmd {
  request(url, "GET", expect~, body=Empty)
}

///|
/// Create a command to send a PUT request.
#cfg(target="js")
pub fn[Model] delete(url : String, expect~ : Expecting[Cmd, Model]) -> Cmd {
  request(url, "DELETE", expect~, body=Empty)
}

///|
/// Create a command to send a POST request.
#cfg(target="js")
pub fn[Model] post(
  url : String,
  body : Body,
  expect~ : Expecting[Cmd, Model],
) -> Cmd {
  request(url, "POST", body~, expect~)
}

///|
/// Create a command to send a PATCH request.
#cfg(target="js")
pub fn[Model] patch(
  url : String,
  body : Body,
  expect~ : Expecting[Cmd, Model],
) -> Cmd {
  request(url, "PATCH", body~, expect~)
}

///|
fn create_company(
  conn : @sqlite3.Connection,
) -> Unit raise @sqlite3.SqliteError {
  let stmt = conn.prepare(
    (
      #|CREATE TABLE COMPANY(
      #|  ID INT PRIMARY KEY     NOT NULL,
      #|  NAME           BLOB    NOT NULL,
      #|  AGE            INT     NOT NULL,
      #|  ADDRESS        BLOB,
      #|  SALARY         REAL
      #|);
    ),
  )
  stmt.step_once()
  stmt.finalize()
}

///|
fn insert_company(
  conn : @sqlite3.Connection,
) -> Unit raise @sqlite3.SqliteError {
  let stmt = conn.prepare(
    (
      #|INSERT INTO COMPANY (ID,NAME,AGE,ADDRESS,SALARY) VALUES (?,?,?,?,?);
    ),
  )
  stmt.bind(index=1, val=1)
  stmt.bind_string_as_blob(index=2, val="Paul")
  stmt.bind(index=3, val=32)
  stmt.bind_string_as_blob(index=4, val="California")
  stmt.bind(index=5, val=20000.00)
  stmt.step_once()
  stmt.finalize()
}

///|
fn select_company(conn : @sqlite3.Connection) -> Unit raise {
  let stmt = conn.prepare(
    (
      #|SELECT * from COMPANY
    ),
  )
  if stmt.step() {
    let column0 : Int = stmt.column(index=0)
    inspect(column0, content="1")
    let column1 : String = stmt.column_blob_as_string(index=1)
    inspect(column1, content="Paul")
    let column3 : String = stmt.column_blob_as_string(index=3)
    inspect(column3, content="California")
    let column4 : Double = stmt.column(index=4)
    inspect(column4, content="20000")
  }
}

///|
test {
  let conn = @sqlite3.Connection::open(":memory:")
  create_company(conn)
  insert_company(conn)
  select_company(conn)
}

///|
using @runtime {type Props}

///|
using @variant {type Variant}

///|
#cfg(target="js")
using @dom {type Event}

///|
#cfg(not(target="js"))
type Event = Unit

///|
struct Attrs(Props)

///|
pub fn Attrs::build() -> Attrs {
  Attrs(Props::new({}, {}, {}, {}))
}

///|
fn Attrs::to_props(self : Attrs) -> Props {
  self.0
}

///|
fn Attrs::copy(self : Attrs) -> Attrs {
  Attrs(self.0.copy())
}

///|
/// Sets raw HTML and bypasses normal escaping.
/// 
/// # Vulnerability Warning
///
/// This is **XSS‑prone** and should
/// only be used with trusted or sanitized input. It affects both HTML and SVG
/// content since the browser will parse the string into DOM nodes.
#internal(xss_vulnerable, "This function may cause xss attack.")
pub fn Attrs::inner_html(self : Attrs, html : String) -> Attrs {
  self.0.props["innerHTML"] = @variant.String(html)
  self.0
}

///|
/// Set a raw attribute.
fn Attrs::attribute(self : Attrs, key : String, value : String) -> Attrs {
  self.0.attrs[key] = value
  self
}

///|
/// Set a property.
fn Attrs::property(self : Attrs, key : String, value : Variant) -> Attrs {
  self.0.props[key] = value
  self
}

///|
/// Set a style declaration.
pub fn Attrs::style(self : Attrs, key : String, value : String) -> Attrs {
  self.0.styles[key] = value
  self
}

// ///|

///|
/// Set an event handler.
pub fn Attrs::handler(
  self : Attrs,
  key : String,
  value : (Event, &@runtime.Scheduler) -> Unit,
) -> Attrs {
  self.0.handlers[key] = value
  self
}

