///|
#cfg(target="js")
fn Attrs::on_mouse_event(
  self : Attrs,
  event : String,
  msg : (MouseEvent) -> Cmd,
) -> Attrs {
  self.handler(event, (event, scheduler) => {
    scheduler.add(msg(event.to_mouse_event().unwrap()))
  })
}

///|
#cfg(not(target="js"))
fn Attrs::on_mouse_event(
  self : Attrs,
  event : String,
  msg : (MouseEvent) -> Cmd,
) -> Attrs {
  ignore((event, msg))
  self
}

