  2→fn init_db(conn : @sqlite3.Connection) -> Unit raise @sqlite3.SqliteError {
  3→  let stmt = conn.prepare(
  4→    (
  5→      #|CREATE TABLE IF NOT EXISTS todos (
  6→      #|  id INTEGER PRIMARY KEY AUTOINCREMENT,
  7→      #|  text BLOB NOT NULL,
