 17→fn todo_to_json(id : Int, text : String, done : Int) -> Json {
 18→  { "id": id, "text": text, "done": done != 0 }
 19→}
 20→
 21→///|
 22→fn get_all_todos(conn : @sqlite3.Connection) -> Array[Json] raise @sqlite3.SqliteError {
 23→  let stmt = conn.prepare("SELECT id, text, done FROM todos ORDER BY id")
 24→  let todos : Array[Json] = []
 25→  while stmt.step() {
 26→    let id : Int = stmt.column(index=0)
 27→    let text : String = stmt.column_blob_as_string(index=1)
 28→    let done : Int = stmt.column(index=2)
 29→    todos.push(todo_to_json(id, text, done))
 30→  }
 31→  stmt.finalize()
 32→  todos
 33→}
 34→
 35→///|
 36→fn create_todo(
 37→  conn : @sqlite3.Connection,
 38→  text : String,
 39→) -> Json raise @sqlite3.SqliteError {
 40→  let stmt = conn.prepare("INSERT INTO todos (text, done) VALUES (?, 0)")
 41→  stmt.bind_string_as_blob(index=1, val=text)
 42→  stmt.step_once()
 43→  stmt.finalize()
 44→  let stmt2 = conn.prepare("SELECT last_insert_rowid()")
 45→  guard stmt2.step()
 46→  let id : Int = stmt2.column(index=0)
 47→  stmt2.finalize()
 48→  todo_to_json(id, text, 0)
 49→}
