 51→///|
 52→fn update_todo(
 53→  conn : @sqlite3.Connection,
 54→  id : Int,
 55→  done : Bool,
 56→) -> Json raise @sqlite3.SqliteError {
 57→  let done_int = if done { 1 } else { 0 }
 58→  let stmt = conn.prepare("UPDATE todos SET done = ? WHERE id = ?")
 59→  stmt.bind(index=1, val=done_int)
 60→  stmt.bind(index=2, val=id)
 61→  stmt.step_once()
 62→  stmt.finalize()
 63→  let stmt2 = conn.prepare("SELECT id, text, done FROM todos WHERE id = ?")
 64→  stmt2.bind(index=1, val=id)
 65→  guard stmt2.step()
 66→  let text : String = stmt2.column_blob_as_string(index=1)
 67→  let done_val : Int = stmt2.column(index=2)
 68→  stmt2.finalize()
 69→  todo_to_json(id, text, done_val)
 70→}
