100→  }
101→  let app = @mocket.new()
102→  app
103→  ..use_middleware(@cors.handle_cors())
104→  ..static_assets("/", @static_file.new("./public"))
105→  ..get("/api/todos", fn(_event) noraise {
106→    try {
107→      let todos = get_all_todos(conn)
108→      @mocket.HttpResponse::new(OK).json(todos)
109→    } catch {
110→      e => @mocket.HttpResponse::new(InternalServerError).body("\{e}")
111→    }
112→  })
