///|
pub fn is_preflight_request(event : @mocket.MocketEvent) -> Bool {
  let origin = event.req.headers.get("origin")
  let access_control_request_method = event.req.headers.get(
    "access-control-request-method",
  )
  return event.req.http_method == "OPTIONS" &&
    origin != None &&
    access_control_request_method != None
}

///|
pub fn append_cors_preflight_headers(
  event : @mocket.MocketEvent,
  origin? : String = "*",
  methods? : String = "*",
  allow_headers? : String = "*",
  credentials? : Bool = false,
  max_age? : Int = 86400,
) -> Unit noraise {
  let headers = event.res.headers
  headers["Access-Control-Allow-Origin"] = origin
  if credentials {
    headers["Access-Control-Allow-Credentials"] = "true"
  }
  headers["Access-Control-Allow-Methods"] = methods
  headers["Access-Control-Allow-Headers"] = allow_headers
  headers["Access-Control-Max-Age"] = max_age.to_string()
}

///|
pub fn append_cors_headers(
  event : @mocket.MocketEvent,
  origin? : String = "*",
  methods? : String = "*",
  allow_headers? : String = "*",
  expose_headers? : String = "*",
  credentials? : Bool = false,
) -> Unit noraise {
  let headers = event.res.headers
  headers["Access-Control-Allow-Origin"] = origin
  headers["Access-Control-Allow-Methods"] = methods
  headers["Access-Control-Allow-Headers"] = allow_headers
  headers["Access-Control-Expose-Headers"] = expose_headers
  if credentials {
    headers["Access-Control-Allow-Credentials"] = "true"
  }
}

///|
pub fn handle_cors(
  origin? : String = "*",
  methods? : String = "*",
  allow_headers? : String = "*",
  expose_headers? : String = "*",
  credentials? : Bool = false,
  max_age? : Int = 86400,
) -> @mocket.Middleware {
  (event, next) => {
    if is_preflight_request(event) {
      append_cors_preflight_headers(
        event,
        origin~,
        methods~,
        allow_headers~,
        credentials~,
        max_age~,
      )
      // 对于预检请求，直接返回空响应，不调用next()
      @mocket.HttpResponse::new(OK).to_responder()
    } else {
      append_cors_headers(
        event,
        origin~,
        methods~,
        allow_headers~,
        expose_headers~,
        credentials~,
      )
      // 对于普通请求，继续执行后续中间件和处理器
      next()
    }
  }
}

///|
pub type MiddlewareNext = async () -> &Responder noraise

///|
// 中间件类型：接受 HttpEvent 和 next 函数，返回 HttpBody
pub type Middleware = async (MocketEvent, MiddlewareNext) -> &Responder noraise

///|
// 注册中间件，支持路径匹配
pub fn Mocket::use_middleware(
  self : Mocket,
  middleware : Middleware,
  base_path? : String,
) -> Unit {
  let base_path = base_path.unwrap_or(self.base_path)
  // 将中间件和路径信息一起存储
  self.middlewares.push((base_path, middleware))
}

///|
// 执行中间件链，支持路径匹配和洋葱模型
pub async fn execute_middlewares(
  middlewares : Array[(String, Middleware)],
  event : MocketEvent,
  final_handler : HttpHandler,
) -> &Responder noraise {
  // 过滤出匹配路径的中间件
  let matched_middlewares = []
  middlewares.each(middleware => {
    let (base_path, middleware) = middleware
    // 如果 base_path 为空字符串，则为全局中间件
    // 否则检查请求路径是否匹配 base_path
    if base_path == "" || event.req.url.has_prefix(base_path) {
      matched_middlewares.push(middleware)
    }
  })

  // 递归构建中间件链（洋葱模型）
  execute_middleware_chain(matched_middlewares, 0, event, final_handler)
}

///|
// 递归执行中间件链
async fn execute_middleware_chain(
  middlewares : Array[Middleware],
  index : Int,
  event : MocketEvent,
  final_handler : HttpHandler,
) -> &Responder noraise {
  if index >= middlewares.length() {
    // 所有中间件都执行完毕，调用最终处理器
    final_handler(event)
  } else {
    // 执行当前中间件
    let current_middleware = middlewares[index]
    let next = async fn() noraise {
      execute_middleware_chain(middlewares, index + 1, event, final_handler)
    }
    current_middleware(event, next)
  }
}

